import React, { useState } from 'react';
import axios from 'axios';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  LineElement,
  PointElement,
  ArcElement,
  Title,
  Tooltip,
  Legend,
} from 'chart.js';
import { Bar, Line, Doughnut } from 'react-chartjs-2';
import './App.css';

// Register ChartJS components
ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  LineElement,
  PointElement,
  ArcElement,
  Title,
  Tooltip,
  Legend
);

const API_BASE = 'http://localhost:5000/api';

function App() {
  const [mode, setMode] = useState('individual');
  const [loading, setLoading] = useState(false);
  const [results, setResults] = useState(null);
  const [batchResults, setBatchResults] = useState(null);

  // Individual analysis state
  const [customerData, setCustomerData] = useState({
    Tenure: 5.0,
    OrderCount: 5.0,
    CashbackAmount: 12000.0,
    DaySinceLastOrder: 7.0,
    HourSpendOnApp: 30.0,
    OrderAmountHikeFromlastYear: 15.0,
    CouponUsed: 1,
    NumberOfDeviceRegistered: 3,
    Complain: 0,
    SatisfactionScore: 3,
    WarehouseToHome: 10.0,
    NumberOfAddress: 4,
    CityTier: 1,
    PreferredLoginDevice: 'Mobile Phone',
    PreferredPaymentMode: 'Credit Card',
    PreferedOrderCat: 'Laptop & Accessory',
    Gender: 'Male',
    MaritalStatus: 'Married'
  });

  // Batch analysis state
  const [batchFile, setBatchFile] = useState(null);

  const handleInputChange = (field, value) => {
    setCustomerData(prev => ({
      ...prev,
      [field]: value
    }));
  };

  const handleIndividualAnalysis = async () => {
    setLoading(true);
    try {
      const response = await axios.post(`${API_BASE}/analyze-single`, {
        customer_data: customerData
      });
      setResults(response.data);
    } catch (error) {
      console.error('Analysis error:', error);
      alert('Error analyzing customer data: ' + (error.response?.data?.error || error.message));
    }
    setLoading(false);
  };

  const handleBatchAnalysis = async () => {
    if (!batchFile) {
      alert('Please select a file');
      return;
    }

    setLoading(true);
    const formData = new FormData();
    formData.append('file', batchFile);

    try {
      const response = await axios.post(`${API_BASE}/analyze-batch`, formData, {
        headers: {
          'Content-Type': 'multipart/form-data'
        }
      });
      setBatchResults(response.data);
    } catch (error) {
      console.error('Batch analysis error:', error);
      alert('Error analyzing batch data: ' + (error.response?.data?.error || error.message));
    }
    setLoading(false);
  };

  const handleFileChange = (e) => {
    setBatchFile(e.target.files[0]);
  };

  const downloadReport = () => {
    if (!results) return;

    const element = document.createElement('a');
    const file = new Blob([results.text_report], { type: 'text/plain' });
    element.href = URL.createObjectURL(file);
    element.download = `customer_churn_report_${new Date().toISOString().slice(0, 16).replace(/[-:]/g, '')}.txt`;
    document.body.appendChild(element);
    element.click();
    document.body.removeChild(element);
  };

  const downloadBatchResults = async () => {
    if (!batchResults) return;

    try {
      const response = await axios.post(`${API_BASE}/download-batch`, {
        batch_data: batchResults.data
      }, {
        responseType: 'blob'
      });

      const url = window.URL.createObjectURL(new Blob([response.data]));
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', `batch_churn_analysis_${new Date().toISOString().slice(0, 16).replace(/[-:]/g, '')}.csv`);
      document.body.appendChild(link);
      link.click();
      link.remove();
    } catch (error) {
      console.error('Download error:', error);
      alert('Error downloading batch results: ' + (error.response?.data?.error || error.message));
    }
  };

  return (
    <div className="App">
      {/* Header */}
      <div className="header-card">
        <div className="header-content">
          <div className="header-left">
            <div className="logo-container">
              <div className="logo">📊</div>
            </div>
            <div className="header-text">
              <h1>🚀 Executive Churn Intelligence Platform</h1>
              <p>Unified predictive insights — action-first, financialized, and presentation-ready</p>
            </div>
          </div>
          <div className="header-right">
            <div className="timestamp">
              📅 Last updated: <strong>{new Date().toLocaleString()}</strong>
            </div>
          </div>
        </div>
      </div>

      {/* Main Content */}
      <div className="main-content">
        {/* Sidebar */}
        <div className="sidebar">
          <div className="sidebar-section">
            <h2>🎯 Analysis Mode</h2>
            <p>Choose your analysis approach</p>
          </div>

          <div className="sidebar-section">
            <div className="mode-selector">
              <button 
                className={`mode-btn ${mode === 'individual' ? 'active' : ''}`}
                onClick={() => setMode('individual')}
              >
                Individual Profile Analysis
              </button>
              <button 
                className={`mode-btn ${mode === 'batch' ? 'active' : ''}`}
                onClick={() => setMode('batch')}
              >
                Batch File Upload
              </button>
            </div>
          </div>

          <div className="sidebar-section">
            <h3>⚡ Quick Actions</h3>
            <button className="action-btn" onClick={downloadReport} disabled={!results}>
              📸 Export Dashboard PDF
            </button>
          </div>
        </div>

        {/* Content Area */}
        <div className="content-area">
          {mode === 'individual' ? (
            <IndividualAnalysis 
              customerData={customerData}
              onInputChange={handleInputChange}
              onAnalyze={handleIndividualAnalysis}
              loading={loading}
              results={results}
              onDownloadReport={downloadReport}
            />
          ) : (
            <BatchAnalysis 
              onFileChange={handleFileChange}
              onAnalyze={handleBatchAnalysis}
              loading={loading}
              results={batchResults}
              onDownloadResults={downloadBatchResults}
            />
          )}
        </div>
      </div>
    </div>
  );
}

// Gauge Chart Component for Risk Score
const GaugeChart = ({ probability }) => {
  const pct = probability * 100;
  let level, color;

  if (pct < 30) {
    level = 'LOW';
    color = '#34d399';
  } else if (pct < 70) {
    level = 'MODERATE';
    color = '#f97316';
  } else {
    level = 'HIGH';
    color = '#ef4444';
  }

  const data = {
    labels: ['Low', 'Moderate', 'High'],
    datasets: [
      {
        data: [30, 40, 30],
        backgroundColor: ['#34d399', '#f97316', '#ef4444'],
        borderWidth: 0,
        circumference: 180,
        rotation: 270,
      },
    ],
  };

  const options = {
    plugins: {
      legend: {
        display: false,
      },
      tooltip: {
        enabled: false,
      },
    },
    cutout: '70%',
    maintainAspectRatio: false,
  };

  const needle = {
    id: 'needle',
    afterDatasetsDraw(chart) {
      const { ctx, data } = chart;
      ctx.save();

      const angle = Math.PI + (1.5 * Math.PI * (pct / 100));
      const cx = chart.chartArea.left + (chart.chartArea.right - chart.chartArea.left) / 2;
      const cy = chart.chartArea.top + (chart.chartArea.bottom - chart.chartArea.top) / 2;
      const radius = (chart.chartArea.bottom - chart.chartArea.top) / 2;

      // Draw needle
      ctx.translate(cx, cy);
      ctx.rotate(angle);
      ctx.beginPath();
      ctx.moveTo(0, -5);
      ctx.lineTo(radius - 20, 0);
      ctx.lineTo(0, 5);
      ctx.closePath();
      ctx.fillStyle = '#1e293b';
      ctx.fill();

      // Draw needle center
      ctx.rotate(-angle);
      ctx.beginPath();
      ctx.arc(0, 0, 8, 0, 2 * Math.PI);
      ctx.fillStyle = '#1e293b';
      ctx.fill();

      ctx.restore();
    },
  };

  return (
    <div className="gauge-container">
      <div className="gauge-chart">
        <Doughnut data={data} options={options} plugins={[needle]} />
        <div className="gauge-center">
          <div className="gauge-value">{pct.toFixed(1)}%</div>
          <div className="gauge-label">{level} RISK</div>
        </div>
      </div>
    </div>
  );
};

// Deviation Chart Component
const DeviationChart = ({ currentData, benchmarkData, directions }) => {
  const rows = [];

  for (const [feature, benchmark] of Object.entries(benchmarkData)) {
    const current = currentData[feature] || benchmark;
    const dirSign = directions[feature] || 1;
    const dev = benchmark !== 0 ? ((current - benchmark) / benchmark) * 100 : 0;
    rows.push({ Feature: feature, Deviation: dev * dirSign });
  }

  const sortedData = rows.sort((a, b) => a.Deviation - b.Deviation);

  const data = {
    labels: sortedData.map(item => item.Feature),
    datasets: [
      {
        label: 'Deviation vs Benchmark',
        data: sortedData.map(item => item.Deviation),
        backgroundColor: sortedData.map(item => 
          item.Deviation > 20 ? '#ef4444' : 
          item.Deviation > 0 ? '#f97316' : '#34d399'
        ),
        borderColor: sortedData.map(item => 
          item.Deviation > 20 ? '#dc2626' : 
          item.Deviation > 0 ? '#ea580c' : '#059669'
        ),
        borderWidth: 1,
      },
    ],
  };

  const options = {
    indexAxis: 'y',
    plugins: {
      title: {
        display: true,
        text: 'Deviation vs Benchmark (Positive = Higher Risk)',
        color: '#f8fafc',
        font: {
          size: 14,
        },
      },
      legend: {
        display: false,
      },
    },
    scales: {
      x: {
        grid: {
          color: '#334155',
        },
        ticks: {
          color: '#94a3b8',
        },
        title: {
          display: true,
          text: 'Deviation (%)',
          color: '#94a3b8',
        },
      },
      y: {
        grid: {
          color: '#334155',
        },
        ticks: {
          color: '#94a3b8',
        },
      },
    },
  };

  return (
    <div className="chart-container">
      <Bar data={data} options={options} />
    </div>
  );
};

// Feature Contribution Chart
const FeatureContributionChart = ({ contributions }) => {
  const topContributions = contributions.slice(0, 10);

  const data = {
    labels: topContributions.map(item => item.Feature),
    datasets: [
      {
        label: 'Contribution Score',
        data: topContributions.map(item => item.Contribution),
        backgroundColor: topContributions.map((item, index) => 
          index < 3 ? '#ef4444' : index > 6 ? '#34d399' : '#f97316'
        ),
        borderColor: topContributions.map((item, index) => 
          index < 3 ? '#dc2626' : index > 6 ? '#059669' : '#ea580c'
        ),
        borderWidth: 1,
      },
    ],
  };

  const options = {
    indexAxis: 'y',
    plugins: {
      title: {
        display: true,
        text: 'Top 10 Key Churn Risk Factors',
        color: '#f8fafc',
        font: {
          size: 14,
        },
      },
      legend: {
        display: false,
      },
    },
    scales: {
      x: {
        grid: {
          color: '#334155',
        },
        ticks: {
          color: '#94a3b8',
        },
        title: {
          display: true,
          text: 'Contribution Score',
          color: '#94a3b8',
        },
      },
      y: {
        grid: {
          color: '#334155',
        },
        ticks: {
          color: '#94a3b8',
        },
      },
    },
  };

  return (
    <div className="chart-container">
      <Bar data={data} options={options} />
    </div>
  );
};

// Value vs Orders Chart
const ValueOrdersChart = ({ currentOrders, benchmarkOrders }) => {
  const data = {
    labels: ['This Customer', 'Company Average'],
    datasets: [
      {
        label: 'Number of Orders',
        data: [currentOrders, benchmarkOrders],
        backgroundColor: ['#06b6d4', '#7c3aed'],
        borderColor: ['#0891b2', '#6d28d9'],
        borderWidth: 1,
      },
    ],
  };

  const options = {
    plugins: {
      title: {
        display: true,
        text: 'Orders vs Company Average',
        color: '#f8fafc',
        font: {
          size: 14,
        },
      },
      legend: {
        display: false,
      },
    },
    scales: {
      y: {
        beginAtZero: true,
        grid: {
          color: '#334155',
        },
        ticks: {
          color: '#94a3b8',
        },
        title: {
          display: true,
          text: 'Number of Orders',
          color: '#94a3b8',
        },
      },
      x: {
        grid: {
          color: '#334155',
        },
        ticks: {
          color: '#94a3b8',
        },
      },
    },
  };

  return (
    <div className="chart-container">
      <Bar data={data} options={options} />
    </div>
  );
};

function IndividualAnalysis({ customerData, onInputChange, onAnalyze, loading, results, onDownloadReport }) {
  const [activeTab, setActiveTab] = useState('core');

  const renderInputField = (label, field, type = 'number', options = null) => {
    if (type === 'select') {
      return (
        <div className="input-group">
          <label>{label}</label>
          <select 
            value={customerData[field]} 
            onChange={(e) => onInputChange(field, e.target.value)}
          >
            {options.map(option => (
              <option key={option} value={option}>{option}</option>
            ))}
          </select>
        </div>
      );
    }

    if (type === 'toggle') {
      return (
        <div className="input-group">
          <label>{label}</label>
          <div className="toggle-group">
            <button 
              type="button"
              className={`toggle-btn ${customerData[field] ? 'active' : ''}`}
              onClick={() => onInputChange(field, 1)}
            >
              Yes
            </button>
            <button 
              type="button"
              className={`toggle-btn ${!customerData[field] ? 'active' : ''}`}
              onClick={() => onInputChange(field, 0)}
            >
              No
            </button>
          </div>
        </div>
      );
    }

    if (type === 'range') {
      return (
        <div className="input-group">
          <label>{label}</label>
          <input 
            type="range"
            min="1"
            max="5"
            value={customerData[field]}
            onChange={(e) => onInputChange(field, parseInt(e.target.value))}
          />
          <div className="range-value">Current: {customerData[field]}</div>
        </div>
      );
    }

    return (
      <div className="input-group">
        <label>{label}</label>
        <input 
          type={type}
          value={customerData[field]}
          onChange={(e) => onInputChange(field, parseFloat(e.target.value) || e.target.value)}
          step={type === 'number' ? 'any' : undefined}
        />
      </div>
    );
  };

  // Benchmark data for charts
  const benchmarkProfile = {
    'Tenure (Months)': 9,
    'Cashback Amount (₹)': 12000,
    'Days Since Last Order': 5,
    'Satisfaction Score': 4,
    'Warehouse Distance (km)': 10,
  };

  const riskDirections = {
    'Tenure (Months)': -1,
    'Cashback Amount (₹)': -1,
    'Days Since Last Order': 1,
    'Satisfaction Score': -1,
    'Warehouse Distance (km)': 1,
  };

  const currentProfile = results ? results.profile : {
    'Tenure (Months)': customerData.Tenure,
    'Cashback Amount (₹)': customerData.CashbackAmount,
    'Days Since Last Order': customerData.DaySinceLastOrder,
    'Satisfaction Score': customerData.SatisfactionScore,
    'Warehouse Distance (km)': customerData.WarehouseToHome,
  };

  return (
    <div className="individual-analysis">
      <h2>👤 Customer Profile Data Input</h2>

      {/* Tabs */}
      <div className="tabs">
        <button 
          className={`tab ${activeTab === 'core' ? 'active' : ''}`}
          onClick={() => setActiveTab('core')}
        >
          💰 Core Metrics
        </button>
        <button 
          className={`tab ${activeTab === 'service' ? 'active' : ''}`}
          onClick={() => setActiveTab('service')}
        >
          🛠️ Service & Logistics
        </button>
        <button 
          className={`tab ${activeTab === 'demographic' ? 'active' : ''}`}
          onClick={() => setActiveTab('demographic')}
        >
          🧑‍ Demographic Data
        </button>
      </div>

      {/* Tab Content */}
      <div className="tab-content">
        {activeTab === 'core' && (
          <div className="tab-panel">
            <div className="input-columns">
              <div className="input-column">
                {renderInputField("1. Customer Lifetime (Months)", "Tenure")}
                {renderInputField("2. Total Orders", "OrderCount")}
                {renderInputField("3. Total Cashback Earned (₹)", "CashbackAmount")}
                {renderInputField("4. Days Since Last Order", "DaySinceLastOrder")}
              </div>
              <div className="input-column">
                {renderInputField("5. App Time (Hours/month)", "HourSpendOnApp")}
                {renderInputField("6. Perceived Price Increase (%)", "OrderAmountHikeFromlastYear")}
                {renderInputField("7. Coupons Used", "CouponUsed")}
                {renderInputField("8. Devices Registered", "NumberOfDeviceRegistered")}
              </div>
            </div>
          </div>
        )}

        {activeTab === 'service' && (
          <div className="tab-panel">
            <div className="input-columns">
              <div className="input-column">
                {renderInputField("9. Has a Formal Complaint?", "Complain", "toggle")}
                {renderInputField("10. Satisfaction Score (1-5)", "SatisfactionScore", "range")}
                {renderInputField("11. Warehouse Distance (km)", "WarehouseToHome")}
                {renderInputField("12. Delivery Addresses", "NumberOfAddress")}
              </div>
              <div className="input-column">
                {renderInputField("15. City Tier", "CityTier")}
                {renderInputField("16. Login Device", "PreferredLoginDevice", "select", ['Mobile Phone', 'Computer'])}
                {renderInputField("17. Payment Mode", "PreferredPaymentMode", "select", ['Debit Card', 'Credit Card', 'UPI', 'E wallet', 'Cash on Delivery'])}
                {renderInputField("18. Order Category", "PreferedOrderCat", "select", ['Laptop & Accessory', 'Mobile Phone', 'Fashion', 'Grocery', 'Books & Stationery', 'Footwear', 'Sports Equipment', 'Others'])}
              </div>
            </div>
          </div>
        )}

        {activeTab === 'demographic' && (
          <div className="tab-panel">
            <div className="input-columns">
              <div className="input-column">
                {renderInputField("13. Gender", "Gender", "select", ['Female', 'Male', 'Other'])}
              </div>
              <div className="input-column">
                {renderInputField("14. Marital Status", "MaritalStatus", "select", ['Single', 'Married', 'Divorced', 'Other'])}
              </div>
            </div>
          </div>
        )}
      </div>

      <button 
        className="analyze-btn primary"
        onClick={onAnalyze}
        disabled={loading}
      >
        {loading ? 'Analyzing...' : '✨ Analyze Customer Risk Now'}
      </button>

      {/* Results */}
      {results && (
        <ResultsDisplay 
          results={results} 
          onDownloadReport={onDownloadReport}
          currentProfile={currentProfile}
          benchmarkProfile={benchmarkProfile}
          riskDirections={riskDirections}
        />
      )}
    </div>
  );
}

function BatchAnalysis({ onFileChange, onAnalyze, loading, results, onDownloadResults }) {
  return (
    <div className="batch-analysis">
      <h2>Bulk Customer Risk Assessment</h2>
      <p>Upload a CSV file containing multiple customer profiles for mass risk segmentation.</p>

      <div className="upload-section">
        <input 
          type="file" 
          accept=".csv"
          onChange={onFileChange}
          className="file-input"
        />
        <button 
          className="analyze-btn primary"
          onClick={onAnalyze}
          disabled={loading}
        >
          {loading ? 'Analyzing...' : '📊 Analyze Batch Data'}
        </button>
      </div>

      {results && (
        <BatchResults 
          results={results}
          onDownloadResults={onDownloadResults}
        />
      )}
    </div>
  );
}

function ResultsDisplay({ results, onDownloadReport, currentProfile, benchmarkProfile, riskDirections }) {
  const riskLevel = results.risk_level;
  const riskColor = riskLevel === 'HIGH' ? '#ef4444' : riskLevel === 'MEDIUM' ? '#f97316' : '#34d399';
  const riskIcon = riskLevel === 'HIGH' ? '🚨' : riskLevel === 'MEDIUM' ? '⚠️' : '✅';

  return (
    <div className="results">
      <h2>✨ Churn Risk Analysis Report</h2>

      {/* Risk Alert */}
      <div className="risk-alert" style={{ borderLeftColor: riskColor }}>
        {riskIcon} <strong>{riskLevel} RISK ({(results.probability * 100).toFixed(1)}%)</strong>: Primary risk factor identified as <strong>{results.top_driver}</strong>.
      </div>

      {/* Executive Summary */}
      <div className="section">
        <h3>EXECUTIVE SUMMARY</h3>
        <p>This customer is currently evaluated at a <strong>{(results.probability * 100).toFixed(2)}%</strong> churn probability and is categorized as {riskLevel.toLowerCase()} risk. We recommend proceeding directly to the action plan below.</p>
      </div>

      {/* KPI Cards */}
      <div className="kpi-grid">
        <div className="kpi-card">
          <div className="kpi-title">Current Churn Risk</div>
          <div className="kpi-value">{(results.probability * 100).toFixed(1)}%</div>
        </div>
        <div className="kpi-card">
          <div className="kpi-title">Customer Tenure</div>
          <div className="kpi-value">{results.profile['Tenure (Months)']} mo</div>
        </div>
        <div className="kpi-card">
          <div className="kpi-title">Days Since Last Order</div>
          <div className="kpi-value">{results.profile['Days Since Last Order']} d</div>
        </div>
        <div className="kpi-card">
          <div className="kpi-title">Satisfaction Score</div>
          <div className="kpi-value">{results.profile['Satisfaction Score']}/5</div>
        </div>
      </div>

      {/* Charts Section */}
      <div className="section">
        <h3>📊 Risk Analysis Dashboard</h3>
        <div className="charts-grid">
          <div className="chart-card">
            <h4>Risk Gauge</h4>
            <GaugeChart probability={results.probability} />
          </div>
          <div className="chart-card">
            <h4>Orders Comparison</h4>
            <ValueOrdersChart 
              currentOrders={results.profile['Total Orders'] || 5}
              benchmarkOrders={8}
            />
          </div>
        </div>

        <div className="charts-grid">
          <div className="chart-card full-width">
            <h4>Feature Deviation Analysis</h4>
            <DeviationChart 
              currentData={currentProfile}
              benchmarkData={benchmarkProfile}
              directions={riskDirections}
            />
          </div>
        </div>

        <div className="charts-grid">
          <div className="chart-card full-width">
            <h4>Risk Factor Contributions</h4>
            <FeatureContributionChart contributions={results.feature_contributions} />
          </div>
        </div>
      </div>

      {/* Business Impact */}
      <div className="section">
        <h3>💼 Business Impact Analysis</h3>
        <div className="kpi-grid">
          <div className="kpi-card">
            <div className="kpi-title">Estimated CLV</div>
            <div className="kpi-value">₹{results.business_impact.estimated_clv.toLocaleString()}</div>
          </div>
          <div className="kpi-card">
            <div className="kpi-title">Retention Budget</div>
            <div className="kpi-value">₹{results.business_impact.retention_budget.toLocaleString()}</div>
          </div>
          <div className="kpi-card">
            <div className="kpi-title">Potential Loss</div>
            <div className="kpi-value">₹{results.business_impact.potential_revenue_loss.toLocaleString()}</div>
          </div>
          <div className="kpi-card">
            <div className="kpi-title">ROI Potential</div>
            <div className="kpi-value">{results.business_impact.roi_retention.toFixed(1)}x</div>
          </div>
        </div>
      </div>

      {/* Feature Contributions */}
      {results.feature_contributions && results.feature_contributions.length > 0 && (
        <div className="section">
          <h3>🔍 Top Risk Factors</h3>
          <div className="feature-list">
            {results.feature_contributions.slice(0, 5).map((feature, index) => (
              <div key={index} className="feature-item">
                <span className="feature-name">{feature.Feature}</span>
                <span className="feature-score">Impact: {feature.Contribution.toFixed(4)}</span>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Download Report */}
      <div className="section">
        <button className="download-btn primary" onClick={onDownloadReport}>
          📥 Download Comprehensive Customer Report (TEXT)
        </button>
      </div>
    </div>
  );
}

function BatchResults({ results, onDownloadResults }) {
  return (
    <div className="batch-results">
      <h2>Batch Analysis Results</h2>

      {/* Summary Cards */}
      <div className="kpi-grid">
        <div className="kpi-card">
          <div className="kpi-title">Total Customers</div>
          <div className="kpi-value">{results.summary.total_customers}</div>
        </div>
        <div className="kpi-card">
          <div className="kpi-title">High-Risk %</div>
          <div className="kpi-value">{results.summary.high_risk_percentage.toFixed(1)}%</div>
        </div>
        <div className="kpi-card">
          <div className="kpi-title">Potential Revenue Loss</div>
          <div className="kpi-value">₹{(results.summary.total_potential_loss / 100000).toFixed(1)} Lakh</div>
        </div>
        <div className="kpi-card">
          <div className="kpi-title">ROI on Retention</div>
          <div className="kpi-value">{results.summary.roi_retention.toFixed(1)}x</div>
        </div>
      </div>

      {/* Risk Distribution */}
      <div className="section">
        <h3>Risk Distribution</h3>
        <div className="risk-distribution">
          {Object.entries(results.risk_distribution).map(([risk, count]) => (
            <div key={risk} className="risk-item">
              <span className="risk-label">{risk}</span>
              <span className="risk-count">{count} customers</span>
            </div>
          ))}
        </div>
      </div>

      {/* Download Button */}
      <div className="section">
        <button className="download-btn primary" onClick={onDownloadResults}>
          📥 Download Batch Results CSV
        </button>
      </div>
    </div>
  );
}

export default App;
